/// Look up an anticipated error by its stable PascalCase code.
pub fn find(code: &str) -> Option<&'static ErrorDef> {
    ERRORS.iter().find(|e| e.code == code)
}

/// Interpolate the `{placeholder}` tokens of `template` from the rejection's JSON `context` object:
/// a token naming a context field renders its value (strings verbatim, other JSON values via their
/// canonical JSON form); a token with no matching field is left as-is (a visible spec/context gap,
/// never a panic).
pub fn interpolate(template: &str, context: &serde_json::Value) -> String {
    let mut out = String::with_capacity(template.len());
    let mut rest = template;
    while let Some(start) = rest.find('{') {
        out.push_str(&rest[..start]);
        let after = &rest[start + 1..];
        match after.find('}') {
            Some(end) => {
                let key = &after[..end];
                match context.get(key) {
                    Some(serde_json::Value::String(s)) => out.push_str(s),
                    Some(v) => out.push_str(&v.to_string()),
                    None => {
                        out.push('{');
                        out.push_str(key);
                        out.push('}');
                    }
                }
                rest = &after[end + 1..];
            }
            None => {
                out.push('{');
                rest = after;
            }
        }
    }
    out.push_str(rest);
    out
}

/// The interpolated English message for `code`, if it is a catalogued error.
pub fn message_en(code: &str, context: &serde_json::Value) -> Option<String> {
    find(code).map(|e| interpolate(e.message_en, context))
}

/// The interpolated French message for `code`, if it is a catalogued error.
pub fn message_fr(code: &str, context: &serde_json::Value) -> Option<String> {
    find(code).map(|e| interpolate(e.message_fr, context))
}
